mapper.update:
UPDATE world_boss_state
SET status = #{status}, last_killer = #{lastKiller}
WHERE server_id = #{serverId} AND boss_id = #{bossId}

UPDATE world_boss_state
SET unit_soldiers = #{unitSoldiers}
WHERE server_id = #{serverId} AND boss_id = #{bossId}

mapper.select:
SELECT user_id AS userId, total_damage AS totalDamage,
       attack_count AS attackCount, cooldown_until AS cooldownUntil
FROM world_boss_damage
WHERE server_id = #{serverId} AND boss_id = #{bossId}
  AND user_id = #{userId} AND window_start_ms = #{windowStartMs}

SELECT user_id AS userId, total_damage AS totalDamage, attack_count AS attackCount
FROM world_boss_damage
WHERE server_id = #{serverId} AND boss_id = #{bossId}
  AND window_start_ms = #{windowStartMs}
ORDER BY total_damage DESC
LIMIT #{limit}
